SELECT * FROM ( SELECT P.POST_ID AS postId, P.BOARD_TYPE AS boardType, P.TITLE AS title, P.VIEW_COUNT AS viewCount, P.STATUS_CD AS statusCd, P.REG_DATE AS regDate, M.NICKNAME AS authorName, (SELECT COUNT(*) FROM TB_POST_REPORT R WHERE R.POST_ID = P.POST_ID) AS reportCount, (SELECT COUNT(*) FROM TB_POST_REPORT R WHERE R.POST_ID = P.POST_ID AND R.STATUS_CD = 'PENDING') AS pendingReportCount, ROW_NUMBER() OVER (ORDER BY P.REG_DATE DESC) AS rn FROM TB_POST P JOIN TB_MEMBER M ON M.MEMBER_NO = P.MEMBER_NO WHERE P.BOARD_TYPE IN ('TOWN', 'SHARE', 'LIFE')
AND (P.TITLE LIKE '%' || #{keyword} || '%' OR M.NICKNAME LIKE '%' || #{keyword} || '%')
AND P.BOARD_TYPE = #{boardType}
AND P.STATUS_CD = #{statusCd}
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{limit}

SELECT COUNT(*) FROM TB_POST P JOIN TB_MEMBER M ON M.MEMBER_NO = P.MEMBER_NO WHERE P.BOARD_TYPE IN ('TOWN', 'SHARE', 'LIFE')
AND (P.TITLE LIKE '%' || #{keyword} || '%' OR M.NICKNAME LIKE '%' || #{keyword} || '%')
AND P.BOARD_TYPE = #{boardType}
AND P.STATUS_CD = #{statusCd}

